262→static int compare_ai_local(const ai_local *aa, const ai_local *ab, int idx)
263→{
264→	int divergences = 0;
265→	int a_val, b_val;
266→	char prefix[64];
267→	snprintf(prefix, sizeof(prefix), "Ai_local[%d]", idx);
268→
269→	CMP_FIELD(prefix, player_awareness_type, aa->player_awareness_type, ab->player_awareness_type);
270→	CMP_FIELD(prefix, retry_count, aa->retry_count, ab->retry_count);
271→	CMP_FIELD(prefix, consecutive_retries, aa->consecutive_retries, ab->consecutive_retries);
272→	CMP_FIELD(prefix, mode, aa->mode, ab->mode);
273→	CMP_FIELD(prefix, previous_visibility, aa->previous_visibility, ab->previous_visibility);
274→	CMP_FIELD(prefix, rapidfire_count, aa->rapidfire_count, ab->rapidfire_count);
275→	CMP_FIELD(prefix, goal_segment, aa->goal_segment, ab->goal_segment);
276→#ifdef BUILD_DESCENT2
277→	CMP_FIELD(prefix, next_action_time, aa->next_action_time, ab->next_action_time);
278→#else
279→	CMP_FIELD(prefix, wait_time, aa->wait_time, ab->wait_time);
280→#endif
281→	CMP_FIELD(prefix, next_fire, aa->next_fire, ab->next_fire);
282→#ifdef BUILD_DESCENT2
283→	CMP_FIELD(prefix, next_fire2, aa->next_fire2, ab->next_fire2);
284→#endif
285→	CMP_FIELD(prefix, player_awareness_time, aa->player_awareness_time, ab->player_awareness_time);
286→	CMP_FIELD(prefix, time_player_seen, aa->time_player_seen, ab->time_player_seen);
287→	CMP_FIELD(prefix, time_player_sound_attacked, aa->time_player_sound_attacked, ab->time_player_sound_attacked);
288→	CMP_FIELD(prefix, next_misc_sound_time, aa->next_misc_sound_time, ab->next_misc_sound_time);
289→	CMP_FIELD(prefix, time_since_processed, aa->time_since_processed, ab->time_since_processed);
290→
291→	for (int i = 0; i < 10; i++) { /* MAX_SUBMODELS = 10 */
292→		if (aa->goal_state[i] != ab->goal_state[i]) {
293→			parity_log("  %s.goal_state[%d]: OCaml=0x%X C=0x%X\n", prefix, i,
294→				(int)aa->goal_state[i], (int)ab->goal_state[i]);
295→			divergences++;
296→		}
297→		if (aa->achieved_state[i] != ab->achieved_state[i]) {
298→			parity_log("  %s.achieved_state[%d]: OCaml=0x%X C=0x%X\n", prefix, i,
299→				(int)aa->achieved_state[i], (int)ab->achieved_state[i]);
300→			divergences++;
301→		}
302→	}
303→
304→	return divergences;
305→}
