  1→/*
  2→ * compare_state_logs.c - Offline comparison of two state log files
  3→ *
  4→ * Compares per-frame game state dumps produced by the input replayer
  5→ * running through two different builds (e.g., C-only vs OCaml bridge).
  6→ *
  7→ * Usage: compare_state_logs <log_a.bin> <log_b.bin>
  8→ *
  9→ * State log format per frame:
 10→ *   uint32_t frame_number
 11→ *   int32_t  n_objects
 12→ *   object   objects[n_objects]
 13→ *   ai_local ai_local_info[n_objects]
 14→ *   player   players[MAX_PLAYERS]
 15→ *   int32_t  globals[5]  (Player_is_dead, Player_exploded, Overall_agitation,
 16→ *                         Highest_object_index, rand_state)
 17→ */
 18→
 19→#include <stdio.h>
 20→#include <stdlib.h>
 21→#include <string.h>
 22→#include <stdint.h>
 23→
 24→/* We don't include game headers here - we compare raw bytes.
 25→ * Object and struct sizes are detected from the log files. */
 26→
 27→#define MAX_OBJECTS 350
 28→#define MAX_PLAYERS 8
 29→
 30→static int verbose = 0;
 31→
 32→typedef struct {
 33→	uint32_t frame;
 34→	int32_t  n_objects;
 35→	int32_t  globals[5];
 36→	/* Raw bytes for objects, ai_local, players follow */
 37→	uint8_t  *object_data;      /* n_objects * object_size */
 38→	uint8_t  *ai_local_data;    /* n_objects * ai_local_size */
 39→	uint8_t  *player_data;      /* MAX_PLAYERS * player_size */
 40→} frame_state;
 41→
 42→/*
 43→ * Read one frame from the state log.
 44→ * Returns bytes of object/ai data read, or -1 on EOF/error.
 45→ * Caller must free object_data, ai_local_data, player_data.
 46→ */
 47→static int read_frame(FILE *f, frame_state *state,
 48→                      size_t object_size, size_t ai_local_size, size_t player_size)
 49→{
 50→	if (fread(&state->frame, sizeof(uint32_t), 1, f) != 1)
 51→		return -1;
 52→
 53→	if (fread(&state->n_objects, sizeof(int32_t), 1, f) != 1)
 54→		return -1;
 55→
 56→	if (state->n_objects < 0 || state->n_objects > MAX_OBJECTS) {
 57→		fprintf(stderr, "ERROR: invalid n_objects %d at frame %u\n",
 58→			state->n_objects, state->frame);
 59→		return -1;
 60→	}
 61→
 62→	size_t obj_bytes = state->n_objects * object_size;
 63→	size_t ai_bytes = state->n_objects * ai_local_size;
 64→	size_t player_bytes = MAX_PLAYERS * player_size;
 65→
 66→	state->object_data = NULL;
 67→	state->ai_local_data = NULL;
 68→	state->player_data = NULL;
 69→
 70→	if (obj_bytes > 0) {
 71→		state->object_data = (uint8_t *)malloc(obj_bytes);
 72→		if (fread(state->object_data, 1, obj_bytes, f) != obj_bytes)
 73→			return -1;
 74→	}
 75→
 76→	if (ai_bytes > 0) {
 77→		state->ai_local_data = (uint8_t *)malloc(ai_bytes);
 78→		if (fread(state->ai_local_data, 1, ai_bytes, f) != ai_bytes)
 79→			return -1;
 80→	}
 81→
 82→	state->player_data = (uint8_t *)malloc(player_bytes);
 83→	if (fread(state->player_data, 1, player_bytes, f) != player_bytes)
 84→		return -1;
 85→
 86→	if (fread(state->globals, sizeof(state->globals), 1, f) != 1)
 87→		return -1;
 88→
 89→	return 0;
 90→}
 91→
 92→static void free_frame(frame_state *state)
 93→{
 94→	free(state->object_data);
 95→	free(state->ai_local_data);
 96→	free(state->player_data);
 97→	state->object_data = NULL;
 98→	state->ai_local_data = NULL;
 99→	state->player_data = NULL;
100→}
101→
102→static int compare_bytes(const uint8_t *a, const uint8_t *b, size_t len,
103→                         const char *label, uint32_t frame, int index)
104→{
105→	int diffs = 0;
106→	for (size_t i = 0; i < len; i++) {
107→		if (a[i] != b[i]) {
108→			diffs++;
109→			if (verbose && diffs <= 10) {
110→				if (index >= 0)
111→					printf("  frame=%u %s[%d] byte %zu: A=0x%02X B=0x%02X\n",
112→						frame, label, index, i, a[i], b[i]);
113→				else
114→					printf("  frame=%u %s byte %zu: A=0x%02X B=0x%02X\n",
115→						frame, label, i, a[i], b[i]);
116→			}
117→		}
118→	}
119→	return diffs;
120→}
121→
122→int main(int argc, char **argv)
123→{
124→	if (argc < 3) {
125→		fprintf(stderr, "Usage: %s [-v] <log_a.bin> <log_b.bin> [object_size] [ai_local_size] [player_size]\n", argv[0]);
126→		fprintf(stderr, "\nCompare two state log files frame-by-frame.\n");
127→		fprintf(stderr, "Optional size args default to common Descent 2 struct sizes.\n");
128→		fprintf(stderr, "Use -v for verbose byte-level diff output.\n");
129→		return 1;
130→	}
131→
132→	int arg_offset = 1;
133→	if (strcmp(argv[1], "-v") == 0) {
134→		verbose = 1;
135→		arg_offset = 2;
136→	}
137→
138→	const char *file_a = argv[arg_offset];
139→	const char *file_b = argv[arg_offset + 1];
140→
141→	/* Default struct sizes for Descent 2 on arm64 macOS */
142→	size_t object_size = (argc > arg_offset + 2) ? (size_t)atoi(argv[arg_offset + 2]) : 268;
143→	size_t ai_local_size = (argc > arg_offset + 3) ? (size_t)atoi(argv[arg_offset + 3]) : 200;
144→	size_t player_size = (argc > arg_offset + 4) ? (size_t)atoi(argv[arg_offset + 4]) : 148;
145→
146→	FILE *fa = fopen(file_a, "rb");
147→	FILE *fb = fopen(file_b, "rb");
148→
149→	if (!fa) { fprintf(stderr, "ERROR: cannot open '%s'\n", file_a); return 1; }
150→	if (!fb) { fprintf(stderr, "ERROR: cannot open '%s'\n", file_b); fclose(fa); return 1; }
151→
152→	printf("Comparing state logs:\n  A: %s\n  B: %s\n", file_a, file_b);
153→	printf("Struct sizes: object=%zu ai_local=%zu player=%zu\n",
154→		object_size, ai_local_size, player_size);
155→
156→	int total_frames = 0;
157→	int divergent_frames = 0;
158→	int total_object_diffs = 0;
159→	int total_ai_diffs = 0;
160→	int total_player_diffs = 0;
161→	int total_global_diffs = 0;
162→
163→	frame_state sa, sb;
164→
165→	while (1) {
166→		int ra = read_frame(fa, &sa, object_size, ai_local_size, player_size);
167→		int rb = read_frame(fb, &sb, object_size, ai_local_size, player_size);
168→
169→		if (ra == -1 && rb == -1)
170→			break;  /* Both done */
171→
172→		if (ra == -1 || rb == -1) {
173→			printf("WARNING: logs have different lengths (A %s, B %s at frame ~%d)\n",
174→				ra == -1 ? "ended" : "continues",
175→				rb == -1 ? "ended" : "continues",
176→				total_frames);
177→			free_frame(&sa);
178→			free_frame(&sb);
179→			break;
180→		}
181→
182→		total_frames++;
183→		int frame_diffs = 0;
184→
185→		if (sa.frame != sb.frame) {
186→			printf("DIVERGE frame number: A=%u B=%u\n", sa.frame, sb.frame);
187→			frame_diffs++;
188→		}
189→
190→		/* Compare n_objects */
191→		int n_compare = sa.n_objects < sb.n_objects ? sa.n_objects : sb.n_objects;
192→
193→		if (sa.n_objects != sb.n_objects) {
194→			printf("DIVERGE frame=%u n_objects: A=%d B=%d\n",
195→				sa.frame, sa.n_objects, sb.n_objects);
196→			frame_diffs++;
197→		}
198→
199→		/* Compare objects */
200→		for (int i = 0; i < n_compare; i++) {
201→			int d = compare_bytes(
202→				sa.object_data + i * object_size,
203→				sb.object_data + i * object_size,
204→				object_size, "object", sa.frame, i);
205→			if (d > 0) {
206→				total_object_diffs++;
207→				if (!verbose)
208→					printf("DIVERGE frame=%u object[%d]: %d byte differences\n",
209→						sa.frame, i, d);
210→				frame_diffs++;
211→			}
212→		}
213→
214→		/* Compare AI local */
215→		for (int i = 0; i < n_compare; i++) {
216→			int d = compare_bytes(
217→				sa.ai_local_data + i * ai_local_size,
218→				sb.ai_local_data + i * ai_local_size,
219→				ai_local_size, "ai_local", sa.frame, i);
220→			if (d > 0) {
221→				total_ai_diffs++;
222→				if (!verbose)
223→					printf("DIVERGE frame=%u ai_local[%d]: %d byte differences\n",
224→						sa.frame, i, d);
225→				frame_diffs++;
226→			}
227→		}
228→
229→		/* Compare players */
230→		for (int i = 0; i < MAX_PLAYERS; i++) {
231→			int d = compare_bytes(
232→				sa.player_data + i * player_size,
233→				sb.player_data + i * player_size,
234→				player_size, "player", sa.frame, i);
235→			if (d > 0) {
236→				total_player_diffs++;
237→				if (!verbose)
238→					printf("DIVERGE frame=%u player[%d]: %d byte differences\n",
239→						sa.frame, i, d);
240→				frame_diffs++;
241→			}
242→		}
243→
244→		/* Compare globals */
245→		for (int i = 0; i < 5; i++) {
246→			if (sa.globals[i] != sb.globals[i]) {
247→				const char *names[] = {"Player_is_dead", "Player_exploded",
248→					"Overall_agitation", "Highest_object_index", "rand_state"};
249→				printf("DIVERGE frame=%u %s: A=%d B=%d\n",
250→					sa.frame, names[i], sa.globals[i], sb.globals[i]);
251→				total_global_diffs++;
252→				frame_diffs++;
253→			}
254→		}
255→
256→		if (frame_diffs > 0)
257→			divergent_frames++;
258→
259→		free_frame(&sa);
260→		free_frame(&sb);
261→	}
262→
263→	fclose(fa);
264→	fclose(fb);
265→
266→	printf("\n=== Summary ===\n");
267→	printf("Frames compared: %d\n", total_frames);
268→	printf("Divergent frames: %d\n", divergent_frames);
269→	printf("Object divergences: %d\n", total_object_diffs);
270→	printf("AI local divergences: %d\n", total_ai_diffs);
271→	printf("Player divergences: %d\n", total_player_diffs);
272→	printf("Global divergences: %d\n", total_global_diffs);
273→
274→	if (divergent_frames == 0) {
275→		printf("\nPARITY CHECK PASSED - zero divergences\n");
276→		return 0;
277→	} else {
278→		printf("\nPARITY CHECK FAILED - %d divergent frames\n", divergent_frames);
279→		return 1;
280→	}
281→}
