1989→//	If a hiding robot gets bumped or hit, he decides to find another hiding place.
1990→void do_ai_robot_hit(object *objp, int type)
1991→{
1992→	if (objp->control_type == CT_AI) {
1993→		if ((type == PA_WEAPON_ROBOT_COLLISION) || (type == PA_PLAYER_COLLISION))
1994→			switch (objp->ctype.ai_info.behavior) {
1995→				case AIB_STILL:
1996→				{
1997→					int	r;
1998→
1999→					//	Attack robots (eg, green guy) shouldn't have behavior = still.
2000→					Assert(Robot_info[objp->id].attack_type == 0);
