  1→/*
  2→ * compare_state_logs.c - Offline comparison of two state log files
  3→ *
  4→ * Compares per-frame game state dumps produced by the input replayer
  5→ * running through two different builds (e.g., C-only vs OCaml bridge).
  6→ *
  7→ * Usage: compare_state_logs <log_a.bin> <log_b.bin>
  8→ *
  9→ * State log format per frame:
 10→ *   uint32_t frame_number
 11→ *   int32_t  n_objects
 12→ *   object   objects[n_objects]
 13→ *   ai_local ai_local_info[n_objects]
 14→ *   player   players[MAX_PLAYERS]
 15→ *   int32_t  globals[5]  (Player_is_dead, Player_exploded, Overall_agitation,
 16→ *                         Highest_object_index, rand_state)
 17→ */
 18→
 19→#include <stdio.h>
 20→#include <stdlib.h>
 21→#include <string.h>
 22→#include <stdint.h>
 23→
 24→/* We don't include game headers here - we compare raw bytes.
 25→ * Object and struct sizes are detected from the log files. */
 26→
 27→#define MAX_OBJECTS 350
 28→#define MAX_PLAYERS 8
 29→
 30→static int verbose = 0;
 31→
 32→typedef struct {
 33→	uint32_t frame;
 34→	int32_t  n_objects;
 35→	int32_t  globals[5];
 36→	/* Raw bytes for objects, ai_local, players follow */
 37→	uint8_t  *object_data;      /* n_objects * object_size */
 38→	uint8_t  *ai_local_data;    /* n_objects * ai_local_size */
 39→	uint8_t  *player_data;      /* MAX_PLAYERS * player_size */
 40→} frame_state;
 41→
 42→/*
 43→ * Read one frame from the state log.
 44→ * Returns bytes of object/ai data read, or -1 on EOF/error.
 45→ * Caller must free object_data, ai_local_data, player_data.
 46→ */
 47→static int read_frame(FILE *f, frame_state *state,
 48→                      size_t object_size, size_t ai_local_size, size_t player_size)
 49→{
 50→	if (fread(&state->frame, sizeof(uint32_t), 1, f) != 1)
 51→		return -1;
 52→
 53→	if (fread(&state->n_objects, sizeof(int32_t), 1, f) != 1)
 54→		return -1;
 55→
 56→	if (state->n_objects < 0 || state->n_objects > MAX_OBJECTS) {
 57→		fprintf(stderr, "ERROR: invalid n_objects %d at frame %u\n",
 58→			state->n_objects, state->frame);
 59→		return -1;
 60→	}
 61→
 62→	size_t obj_bytes = state->n_objects * object_size;
 63→	size_t ai_bytes = state->n_objects * ai_local_size;
 64→	size_t player_bytes = MAX_PLAYERS * player_size;
 65→
 66→	state->object_data = NULL;
 67→	state->ai_local_data = NULL;
 68→	state->player_data = NULL;
 69→
 70→	if (obj_bytes > 0) {
 71→		state->object_data = (uint8_t *)malloc(obj_bytes);
 72→		if (fread(state->object_data, 1, obj_bytes, f) != obj_bytes)
 73→			return -1;
 74→	}
 75→
 76→	if (ai_bytes > 0) {
 77→		state->ai_local_data = (uint8_t *)malloc(ai_bytes);
 78→		if (fread(state->ai_local_data, 1, ai_bytes, f) != ai_bytes)
 79→			return -1;
 80→	}
 81→
 82→	state->player_data = (uint8_t *)malloc(player_bytes);
 83→	if (fread(state->player_data, 1, player_bytes, f) != player_bytes)
 84→		return -1;
 85→
 86→	if (fread(state->globals, sizeof(state->globals), 1, f) != 1)
 87→		return -1;
 88→
 89→	return 0;
 90→}
 91→
 92→static void free_frame(frame_state *state)
 93→{
 94→	free(state->object_data);
 95→	free(state->ai_local_data);
 96→	free(state->player_data);
 97→	state->object_data = NULL;
 98→	state->ai_local_data = NULL;
 99→	state->player_data = NULL;
100→}

